def sum(n):
    if n == 0:
        return 0
    return n + sum(n - 1)

def sine(x):
    if abs(x) < 0.0001:
        return x
    s = sine(x / 3)
    return 3 * s - 4 * s ** 3

def oddCount(L):
    if not L:
        return 0
    return (1 if L[0] % 2 != 0 else 0) + oddCount(L[1:])

def oddSum(L):
    if not L:
        return 0
    first = L[0] if L[0] % 2 != 0 else 0
    return first + oddSum(L[1:])

def oddsOnly(L):
    if not L:
        return []
    rest = oddsOnly(L[1:])
    if L[0] % 2 != 0:
        return [L[0]] + rest
    return rest

def maxOdd(L):
    if not L:
        return None
    rest = maxOdd(L[1:])
    if L[0] % 2 != 0:
        if rest is None:
            return L[0]
        return max(L[0], rest)
    return rest

def hasConsecutiveDigits(n):
    n = abs(n)
    if n < 10:
        return False
    return (n % 10 == (n // 10) % 10) or hasConsecutiveDigits(n // 10)

def alternatingSum(L):
    if not L:
        return 0
    return L[0] - alternatingSum(L[1:])

def is_palindrome(strng):
    if len(strng) <= 1:
        return True
    return strng[0] == strng[-1] and is_palindrome(strng[1:-1])

def num_eights(pos):
    if pos == 0:
        return 0
    return (1 if pos % 10 == 8 else 0) + num_eights(pos // 10)

def merge(dict1, dict2):
    if not dict1:
        return dict(dict2)
    key = next(iter(dict1))
    val = dict1[key]
    rest = {k: v for k, v in dict1.items() if k != key}
    merged = merge(rest, dict2)
    if key in merged:
        merged[key] += val
    else:
        merged[key] = val
    return merged

def mario_number(level):
    def helper(i):
        if i == len(level) - 1:
            return 1
        if i >= len(level) or level[i] == 'P':
            return 0
        return helper(i + 1) + helper(i + 2)
    return helper(0)

def knapsack(weights, values, c):
    if not weights or c == 0:
        return 0
    if weights[0] > c:
        return knapsack(weights[1:], values[1:], c)
    skip = knapsack(weights[1:], values[1:], c)
    take = values[0] + knapsack(weights[1:], values[1:], c - weights[0])
    return max(skip, take)
